import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Request
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

interface ApiService {
    @GET("users")
    suspend fun fetchUsers(): List<User>

    companion object {
        private const val BASE_DEV_URL = "https://dev.api.example.com/"
        private const val BASE_STAGING_URL = "https://staging.api.example.com/"
        private const val BASE_PROD_URL = "https://api.example.com/"

        fun create(environment: Environment, authToken: String): ApiService {
            val baseUrl = when (environment) {
                Environment.DEV -> BASE_DEV_URL
                Environment.STAGING -> BASE_STAGING_URL
                Environment.PROD -> BASE_PROD_URL
            }

            val client = OkHttpClient.Builder()
                .addInterceptor(AuthInterceptor(authToken))
                .build()

            return Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build()
                .create(ApiService::class.java)
        }
    }
}

class AuthInterceptor(private val authToken: String) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): okhttp3.Response {
        val original: Request = chain.request()
        val request = original.newBuilder()
            .header("Authorization", "Bearer $authToken")
            .method(original.method, original.body)
            .build()

        return chain.proceed(request)
    }
}

enum class Environment {
    DEV,
    STAGING,
    PROD
}

